// Format angka ke Rupiah
function fmt(n) {
  const num = Number(n) || 0;
  return new Intl.NumberFormat('id-ID', {
    style: 'currency',
    currency: 'IDR',
    maximumFractionDigits: 0
  }).format(num);
}

function fmtDiff(val, pct) {
  if (val === null || val === undefined) return '—';
  const num = Number(val) || 0;
  const arrow = num >= 0 ? '↑' : '↓';
  const sign  = num >= 0 ? '+' : '';
  const pctStr = pct !== null && pct !== undefined ? ` (${sign}${pct}%)` : '';
  return `${arrow} ${sign}${fmt(Math.abs(num))}${pctStr}`;
}

// Ambil data — defensive null check
// API returns: { success: true, data: { date, summary, comparison, platforms, stokKritis, aging } }
const raw = $input.item.json;

// Debug: jika API error, tampilkan di pesan
if (raw?.success === false) {
  return [{ json: { message: `⚠️ API Error: ${raw.error || 'Unknown error'}` } }];
}

const d = raw?.data || raw || {};
const s = d.summary || {};
const c = d.comparison || {};
const platforms = Array.isArray(d.platforms) ? d.platforms : [];
const aging = d.aging || { total: 0, detail: {} };

// Baris platform
const platformLines = platforms.length > 0
  ? platforms.map(p => `├ ${(p.platform || 'Unknown').padEnd(8)} : ${fmt(p.omzet)} (${p.count || 0} order)`).join('\n')
  : '├ Tidak ada data platform';

// Aging backlog
const agingDetail = aging.detail || {};
const agingStr = Object.keys(agingDetail).length > 0
  ? Object.entries(agingDetail).map(([k, v]) => `├ ${k}: ${v}`).join('\n')
  : '├ Tidak ada';

// Tanggal dalam format Indonesia
const dateStr = d.date || new Date().toISOString().slice(0, 10);
const tgl = new Date(dateStr + 'T00:00:00+07:00').toLocaleDateString('id-ID', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const omzet = Number(s.omzet) || 0;
const hpp   = Number(s.hpp) || 0;
const gp    = Number(s.grossProfit) || 0;
const margin = omzet > 0 ? ((gp / omzet) * 100).toFixed(1) : '0';

// Comparison vs kemarin
const prevOmzet = Number(c.prevOmzet) || 0;
const omzetDiff = Number(c.omzetDiff) || 0;
const omzetDiffPct = c.omzetDiffPct;
const orderCountDiff = Number(c.orderCountDiff) || 0;

const omzetCompare = prevOmzet > 0
  ? `${omzetDiff >= 0 ? '↑' : '↓'} ${fmt(Math.abs(omzetDiff))}${omzetDiffPct ? ` (${omzetDiff >= 0 ? '+' : ''}${omzetDiffPct}%)` : ''}`
  : '—';
const orderCompare = `${orderCountDiff >= 0 ? '↑' : '↓'} ${Math.abs(orderCountDiff)} order`;

const msg = [
  `📊 *LAPORAN HARIAN ELYASR*`,
  `${tgl} — 17.30 WIB`,
  ``,
  `💰 *OMZET & PROFIT (Hari Ini)*`,
  `├ Real Omzet    : ${fmt(s.omzet)}`,
  `├ HPP Total     : ${fmt(s.hpp)}`,
  `└ Gross Profit  : ${fmt(s.grossProfit)} (${margin}%)`,
  ``,
  `📦 *ORDER*`,
  `├ Total Masuk  : ${s.totalOrder || 0} order`,
  `├ Terkirim     : ${s.terkirim || 0} order`,
  `├ Pending Kirim: ${s.perluKirim || 0} order`,
  `└ Dibatalkan   : ${s.batal || 0} order`,
  ``,
  `🏪 *PER PLATFORM*`,
  platformLines,
  ``,
  `😡 *AGING BACKLOG* (${aging.total || 0} order pending)`,
  agingStr,
  ``,
  `🔥 *STOK KRITIS*: ${d.stokKritis || 0} SKU perlu restock`,
  ``,
  `📈 *VS KEMARIN*`,
  `├ Omzet  : ${omzetCompare}`,
  `└ Order  : ${orderCompare}`,
  ``,
  `_This message was sent automatically with n8n_`
].join('\n');

return [{ json: { message: msg } }];
